// src/components/Profile.js
import React, { useState, useEffect, useRef } from "react";
import { FaUserCircle, FaTimes, FaChevronRight } from "react-icons/fa";
import "./Profile.css";

export default function Profile({ user, onLogout }) {
  const [open, setOpen] = useState(false);
  const sidebarRef = useRef();

  // Disable background scroll when sidebar is open
  useEffect(() => {
    document.body.style.overflow = open ? "hidden" : "";
    return () => (document.body.style.overflow = "");
  }, [open]);

  // Close on ESC key
  useEffect(() => {
    const handleKey = (e) => e.key === "Escape" && setOpen(false);
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, []);

  // Close when clicking outside
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (open && sidebarRef.current && !sidebarRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [open]);

  const handleLogout = () => {
    setOpen(false);
    if (typeof onLogout === "function") onLogout();
  };

  return (
    <>
      {/* Profile Icon (always visible) */}
      <div className="profile-wrapper" title="Profile">
        <FaUserCircle
          className="profile-icon"
          size={36}
          onClick={() => setOpen(true)}
        />
      </div>

      {/* Overlay */}
      <div className={`profile-overlay ${open ? "visible" : ""}`} />

      {/* Sidebar */}
      <aside ref={sidebarRef} className={`profile-sidebar ${open ? "open" : ""}`}>
        <button className="profile-close" onClick={() => setOpen(false)}>
          <FaTimes />
        </button>

        <div className="profile-box">
          <FaUserCircle className="profile-avatar" size={90} />
          <h3 className="profile-name">{user?.name || "Guest User"}</h3>
          <p className="profile-email">{user?.email || "guest@example.com"}</p>
        </div>

        <div className="profile-menu">
          {["Profile", "History", "Orders", "Wishlist"].map((item) => (
            <div key={item} className="profile-menu-item">
              {item}
              <FaChevronRight className="menu-arrow" />
            </div>
          ))}
        </div>

        <button className="logout-btn" onClick={handleLogout}>
          Logout
        </button>
      </aside>
    </>
  );
}
